<!-- 蓝色简洁登录页面 -->
<template>
	<view class="page">
		<slideCode v-if="slideCode[0].show" :session_id="session_id[0]" @close="slideCode[0].show = false"
			@success="$slideCode_success(0, $event)"></slideCode>
		<regPay ref="regpay" @success="handelPaySuccess" />
		<OpenWind :type="openWinType" />

		<view class="login-box" :style="[loginBoxStyle]">
			<view class="login-wrap">
				<view class="logo-box">
					<view style="display: flex;justify-content: center;">
						<u-image :src="$util.img(logo)" width="360rpx" height="160rpx" mode="aspectFit"
							v-if="sysconfig.login_menu.site_in_page_choose == 1" />
						<u-image :src="$util.img(logo)" width="360rpx" height="160rpx" mode="aspectFit"
							@click="$util.on('/pages/index/index')" v-else />
					</view>
					<view class="title">
						{{currLoginTypeName}}
					</view>
				</view>
				<view class="form-wrap">
					<account-view ref="account" v-show="currLoginType =='password'" />
					<sms-view ref="sms" v-show="currLoginType =='mobile'" />
					<email-view ref="email" v-show="currLoginType =='email'" />
				</view>
				<need-know />
				<third-list ref="third-list" />
				<agree-popup v-model="agreePopup" @refuse="handelRefuse" @agree="handelAgree" />
			</view>
		</view>
	</view>
</template>
<script>
	import slideCode from '@/components/slideCode.vue'
	import regPay from '@/components/reg-pay'
	import OpenWind from '@/components/OpenWind'
	import AccountView from './components/login/views/Account'
	import EmailView from './components/login/views/Email'
	import SmsView from './components/login/views/Sms'
	import NeedKnow from './components/login/NeedKnow'
	import Third from './components/login/Third'
	import AgreePopup from './components/login/AgreePopup'

	import {
		mapGetters,
		mapActions,
		mapMutations
	} from 'vuex'

	export default {
		components: {
			slideCode,
			regPay,
			OpenWind,
			'account-view': AccountView,
			'email-view': EmailView,
			'sms-view': SmsView,
			'need-know': NeedKnow,
			'third-list': Third,
			'agree-popup': AgreePopup,
		},
		data() {
			return {
				redirect: '',
				slideCode: [{
					show: false
				}],
				session_id: [],
			};
		},
		computed: {
			...mapGetters({
				icoimg: 'loginConfig/icoimg',
				logo: 'loginConfig/logo',
				currLoginType: 'loginConfig/currLoginType',
				currLoginTypeName: 'loginConfig/currLoginTypeName',
				openWinType: 'loginConfig/openWinType',
				h5LoginBgOpen: 'loginConfig/h5LoginBgOpen',
				h5LoginBgImg: 'loginConfig/h5LoginBgImg',
				showAgreePopup: 'loginConfig/showAgreePopup',
				isThirdLogin: 'loginConfig/isThirdLogin',
			}),
			loginBoxStyle() {
				const re = {}
				if (this.h5LoginBgOpen) {
					re.backgroundImage = `url(${this.$util.img2(this.h5LoginBgImg)})`
					re.backgroundSize = '100% 100%'
					re.backgroundRepeat = 'no-repeat'
				}
				return re
			},
			agreePopup: {
				get() {
					return this.showAgreePopup
				},
				set(v) {
					this.setShowAgreePopup(v)
				}
			}
		},
		provide() {
			return {
				showSlideCode: () => {
					this.slideCode[0].show = true
				},
				getSlideCode: () => this.slideCode[0],
				getSession: () => this.session_id[0],
				getRegPayIns: () => this.$refs['regpay'],
				getRedirect: () => this.redirect,
				getPid: () => {
					return uni.getStorageSync('pid')
				}
			}
		},
		onLoad(e) {
			if (uni.getStorageSync('token')) {
				this.$util.redirect('/pages/index/index')
			} else {
				if (e.redirect == '_store') {
					this.redirect = uni.getStorageSync('callback_url')
				} else {
					this.redirect = this.$Route.query.redirect
				}
				this.setOpenWinType('user_login_open_window')
				this.loadLoginConf()
				this.$slideCode_init(0); //初始化图形滑块
			}
		},

		methods: {
			...mapActions({
				loadLoginConf: 'loginConfig/loadLoginConf'
			}),
			...mapActions(['getUserInfo']),
			...mapMutations({
				setOpenWinType: 'loginConfig/setOpenWinType',
				setShowAgreePopup: 'loginConfig/setShowAgreePopup',
				setAgreeUser: 'loginConfig/setAgreeUser'
			}),
			$getRandomNunber(start, end) {
				return Math.floor(Math.random() * (end - start) + start)
			},
			$slideCode_init(index) {
				this.session_id[index] = this.$getRandomNunber(0, 999999999); //唯一id
				this.slideCode[index].yanzheng = false; //图形验证码是否验证通过
				this.slideCode[index].x = 0 //图形验证码的水平偏移值
			},
			$slideCode_success(index, data) {
				this.slideCode[index].yanzheng = true //验证通过
				this.slideCode[index].x = data.x //偏移值
				uni.$emit('verifySuccess')
			},
			// 付费注册成功回调
			async handelPaySuccess({
				token
			}) {
				//存储token
				uni.setStorageSync('token', token)
				this.$u.vuex('token', token)
				this.$util.msg('登录成功')
				await this.getUserInfo()
				setTimeout(() => {
					if (this.redirect)
						this.$util.redirect(this.redirect)
					else
						this.$util.back()
				}, 1500)
			},
			handelRefuse() {
				this.setShowAgreePopup(false)
			},
			handelAgree() {
				this.setShowAgreePopup(false)
				this.setAgreeUser(true)
				if (!this.isThirdLogin) {
					if (this.currLoginType == 'password') {
						this.$refs['account'].submit()
					} else if (this.currLoginType == 'mobile') {
						this.$refs['sms'].submit()
					} else if (this.currLoginType == 'email') {
						this.$refs['email'].submit()
					}
				} else {
					this.$refs['third-list'].doThirdLogin()
				}
			},
		}
	};
</script>

<style lang="scss" scoped scoped>
	.page {
		position: relative;
		background-color: #fff;
		// background-color: transparent;
	}

	.login-box {
		position: absolute;
		left: 50%;
		transform: translateX(-50%);
		width: 750rpx;
		height: 100%;
		padding: 40rpx;
		border-radius: 4px;
		background: #fff;
		// background: url('/static/6.jpg');
		background-repeat: no-repeat;
		background-size: cover;
		background-position: center;

		.login-wrap {
			padding: 20rpx;
			margin-top: 40rpx;
		}

		.logo-box {
			.title {
				width: 100%;
				color: #1e2331;
				font-weight: 600;
				font-size: 44rpx;
				margin-top: 16rpx;
			}
		}

		.form-wrap {
			margin-top: 40rpx;
		}
	}
</style>