<template>
	<view>
		<u-popup v-model="showLayer" mode="center" width="80%" :closeable="false" border-radius="10">
			<view class="content-box"
				:style="{backgroundImage:`url(${$util.img('/statics/uni/img/index/home_mark_bg.png')})`}">
				<view class="title">{{title}}</view>
				<view class="content-wrap">
					<scroll-view :scroll-y="true" class="html-box" show-scrollbar>
						<u-parse :html="content"></u-parse>
					</scroll-view>
				</view>
				<view class="btn-box">
					<u-button type="primary" shape="square" @click="close">知道了</u-button>
					<!-- <view class="btn"  @click="close">知道了</view> -->
				</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		props: {
			type: {
				type: String,
				default: ''
			},
			title: {
				type: String,
				default: '系统公告'
			},
			showType: {
				type: Number,
				default: 1
			},
		},
		data() {
			return {
				showLayer: false,
				content: ''
			}
		},
		options: {
			styleIsolation: 'shared'
		},
		watch: {
			type(nv) {
				if (nv) {
					this.fetchData()
				}
			}
		},
		mounted() {

			this.fetchData()

		},
		methods: {
			show(content) {
				if (content) {
					this.content = content
				}


				this.showLayer = true


			},
			close() {
				this.showLayer = false
			},
			async fetchData() {

				if (this.showType == 1) {
					const {
						is_open_window, //是否弹窗
						open_window, //弹窗内容
						open_window_md5, //弹窗md5
						open_window_count, //弹窗类型0=1次(缓存),1=每次访问都单
					} = await this.$u.api.indexOpenWindow({
						type: this.type
					})
					if (is_open_window) {

						if (open_window) {
							this.content = open_window
							if (open_window_count == 1) {
								if (open_window_md5 != uni.getStorageSync(`${open_window_md5}:${this.type}`)) {
									uni.setStorageSync(`${is_open_window}:${this.type}`, 1)
									uni.setStorageSync(`${open_window_md5}:${this.type}`, open_window_md5)
									this.showLayer = true
								} else if (!uni.getStorageSync(`${is_open_window}:${this.type}`)) {
									uni.setStorageSync(`${is_open_window}:${this.type}`, 1)
									uni.setStorageSync(`${open_window_md5}:${this.type}`, open_window_md5)
									this.showLayer = true
								}
							} else {
								this.showLayer = true
							}
						}

					}
				}




			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.u-mode-center-box {
			background-color: transparent !important;
		}
	}

	/*滚动条整体粗细样式*/
	::v-deep ::-webkit-scrollbar {
		/*高宽分别对应横竖滚动条的尺寸*/
		width: 8px;
		height: 8px;
	}

	/*滚动条里面小方块*/
	::v-deep ::-webkit-scrollbar-thumb {
		border-radius: 10px !important;
		box-shadow: inset 0 0 5px rgba(0, 0, 0, 0.2) !important;
		/* 颜色 */
		/* background:#b6b6b6!important; */
		/* 线性渐变背景 */
		background-image: linear-gradient(45deg, #ffbd61 25%, #ffbd61 25%, #ff8800 25%, #ff8800 50%, #ffbd61 50%, #ffbd61 75%, #ff8800 75%, #ff8800 100%) !important;
	}

	/*滚动条轨道*/
	::v-deep ::-webkit-scrollbar-track {
		border-radius: 10px !important;
		box-shadow: inset 0 0 5px rgba(0, 0, 0, 0.2) !important;
		background: #EDEDED !important;
	}

	.content-box {
		position: relative;
		background-repeat: no-repeat;
		background-position: 0 0;
		background-size: 100%;
		min-height: 600rpx;
		width: 600rpx;
		margin: 0 auto;
		padding-top: 140rpx;

		.title {
			text-align: center;
			padding: 20rpx 0;
			font-weight: 700;
		}

		.content-wrap {

			padding: 0 20rpx;
			background-color: #fff;

			.html-box {
				// font-size: 28rpx;
				min-height: 200rpx;
				max-height: 640rpx;
				padding-bottom: 144rpx;
			}


		}

		.btn-box {
			text-align: center;
			position: absolute;
			bottom: 30rpx;
			left: 50%;
			transform: translateX(-50%);

			// .btn {
			// 	color: #fff !important;
			// 	display: inline-block;
			// 	background-image: linear-gradient(to right, #FA5A4B, #FF9B7A);
			// 	width: 260rpx;
			// 	padding: 20rpx 0;
			// 	border-radius: 100rpx;
			// }
			::v-deep {
				.u-btn--primary {
					background-image: linear-gradient(to right, #FA5A4B, #FF9B7A);
					border-color:#FA5A4B;
					background-color:#FA5A4B;
					border-radius: 40rpx;
					width: 260rpx;
				}
				.u-primary-hover{
					background-color: rgba(250,90,75,.8) !important;
				}
			}
		}
	}
</style>