<template>
	<view class="third-box" v-if="loginList.length>0">
		<text class="text">第三方登录/注册</text>
		<view class="third-list">
			<view class="third-btn" @click="third_login(item)" v-for="(item,index) in loginList" :key="index">
				<image class="third-logo" :src="$util.img(item.img)" mode="aspectFit"></image>
				<!-- #ifdef MP -->
				<!-- 微信小程序退出登录会有盗刷短信风险 必须隐藏退出登录 缓存中有mobile就不再获取手机号 -->
				<u-button :custom-style="customStyle" open-type="getPhoneNumber"
					@getphonenumber="getPhoneNumberHandler"></u-button>
				<!-- #endif -->
			</view>
		</view>
		<qrcode-dialog ref="qrcode-dialog" @fail="handelCertifyFail" @success="handelCertifySuccess" />
	</view>
</template>

<script>
	import {
		mapGetters,
		mapMutations
	} from 'vuex'
	import QrcodeDialog from './QrcodeDialog'

	export default {
		components: {
			'qrcode-dialog': QrcodeDialog
		},
		data() {
			return {
				customStyle: {
					position: 'absolute',
					opacity: 0,
					width: '64rpx',
					height: '64rpx',
					top: '0',
					left: '0',
					padding: '0',
				},
				currThird: null
			}
		},
		computed: {
			...mapGetters({
				loginList: 'loginConfig/loginList',
				agreeUser: 'loginConfig/agreeUser',
				showAgreePopup: 'loginConfig/showAgreePopup',
			}),
			redirect() {
				return this.getRedirect()
			},
		},
		inject: ['getRegPayIns', 'getRedirect'],
		watch: {
			showAgreePopup(nv, ov) {

			}
		},
		methods: {
			...mapMutations({
				setShowAgreePopup: 'loginConfig/setShowAgreePopup',
				setIsThirdLogin: 'loginConfig/setIsThirdLogin',
			}),
			//第三方登录
			third_login(item) {
				if (!item)
					return
				this.currThird = item

				if (!this.agreeUser) {
					// this.$util.msg('请先阅读并同意用户协议和隐私政策');
					this.setShowAgreePopup(true)
					this.setIsThirdLogin(true)
					return;
				}

				this.doThirdLogin()
			},
			doThirdLogin() {
				let item = this.currThird
				// 是否微信公众号扫码登录
				let is_wx_official_scan = item.name == 'weixin' && item.wx_login_type == 2
				if (is_wx_official_scan) {
					this.$refs['qrcode-dialog'].show({
						redirect: this.redirect
					})
					return
				}
				//#ifdef H5	
				this.$util.msg('三方登录跳转中', 10000);
				window.location.href = `${item.url}?return_url=${this.redirect?this.redirect:''}`
				//#endif
				switch (item.name) {
					case 'qq':
						break;
					case 'weixin': //微信小程序
						//#ifdef MP-WEIXIN
						this.wxxcxLogin()
						//#endif

						//#ifdef APP
						this.wxappLogin()
						//#endif
						break;
				}
			},
			getPhoneNumberHandler(e) {
				this.wxxcx_code2 = e.detail.code
				this.wxxcxLogin()
			},
			wxxcxLogin() {
				var that = this

				uni.showLoading({
					title: `登录中`
				})

				uni.login({
					provider: 'weixin',
					success: function(loginRes) {
						that.wxxcx_code = loginRes.code

						uni.getUserInfo({
							success: function(res2) {
								that.$u.api.login({
										code: that.wxxcx_code,
										codeMobile: that.wxxcx_code2,
										encryptedData: res2.encryptedData,
										iv: res2.iv,
										login_type: 3,
									})
									.then(res => {
										if (res.reg_status == 1) {
											that.getRegPayIns().show({
												reg_code: res.reg_data.reg_code
											})
										} else {
											res.userinfo.isLogin = true
											uni.setStorageSync('token', res.token)
											that.$u.vuex('userinfo', res.userinfo)
											that.$u.vuex('token', res.token)
											uni.hideLoading()

											that.$util.msg('登录成功');

											that.$u.api.bindPid({
												pid: uni.getStorageSync('pid')
											})
											setTimeout(() => {
												if (that.redirect)
													that.$util.redirect(that.redirect)
												else
													that.$util.back()
											}, 1500)
										}



									}).catch(err => {})

							}
						})
					}
				})
			},
			wxappLogin() {


				let that = this

				if (!this.agreeUser) {
					this.$util.msg('请先阅读并同意用户协议和隐私政策');
					return;
				}

				uni.showLoading({
					title: `登录中`
				})

				uni.login({
					provider: 'weixin',
					success: function(loginRes) {
						console.log(loginRes);

						// 获取用户信息
						uni.getUserInfo({
							provider: 'weixin',
							success: function(infoRes) {
								infoRes.userInfo.login_type = 5
								that.$u.api.login(infoRes.userInfo)
									.then(res => {
										if (res.reg_status == 1) {
											that.getRegPayIns().show({
												reg_code: res.reg_data.reg_code
											})
										} else {
											res.userinfo.isLogin = true
											uni.setStorageSync('token', res.token)
											that.$u.vuex('userinfo', res.userinfo)
											that.$u.vuex('token', res.token)
											uni.hideLoading()

											that.$util.msg('登录成功');

											that.$u.api.bindPid({
												pid: uni.getStorageSync('pid')
											})
											setTimeout(() => {
												if (that.redirect)
													that.$util.redirect(that.redirect)
												else
													that.$util.back()
											}, 1000)

										}

									}).catch(err => {})
							},

							fail() {
								that.$util.msg(`获取用户信息失败`)
							},
							complete() {
								uni.hideLoading()
							}
						});
					},
					fail(e) {
						console.log(e);
						that.$util.msg(`登录失败`)
						uni.hideLoading()
					}
				});
			},
			handelCertifyFail(e) {
				console.log(e)
			},
			handelCertifySuccess(e) {
				console.log(e)
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.third-box {

		width: 100%;
		margin-top: 120rpx;
		margin-bottom: 20rpx;
		display: flex;
		align-items: center;
		justify-content: flex-start;
		flex-direction: column;
		gap: 20rpx;

		.text {
			font-weight: 400;
			color: #9b9fa8;
			font-size: 24rpx;
			position: relative;
		}

		.text::before {
			content: "";
			width: 140rpx;
			height: 2rpx;
			background: #D6DAE2;
			position: absolute;
			display: block;
			top: 50%;
			transform: translateY(-50%);
			right: 200rpx;
		}

		.text::after {
			content: "";
			width: 140rpx;
			height: 2rpx;
			background: #D6DAE2;
			position: absolute;
			display: block;
			top: 50%;
			transform: translateY(-50%);
			left: 200rpx;
		}





		.third-list {
			display: flex;
			align-items: center;
			justify-content: center;
			gap: 110rpx;
			position: relative;

			.third-btn {
				position: relative;

				.third-logo {
					width: 64rpx;
					height: 64rpx;
					color: #cacdd5;
				}
			}
		}
	}
</style>