<template>
	<view class="login-form">
		<u-form :model="form" ref="uForm" :label-width="0" :error-type="['toast']" :border-bottom="false">
			<u-form-item prop="mobile" :border-bottom="false">
				<u-input v-model="form.mobile" placeholder="请输入手机号" :height="80" />
			</u-form-item>
			<u-form-item prop="validateCode" :border-bottom="false">
				<view class="input-block">
					<u-input v-model="form.validateCode" placeholder="请输入验证码" :height="80" :maxlength="6"
						:clearable="false" />
					<view class="code-btn" :class="{waiting:is_sendCode===true}" @click="sendCode">{{tips}}</view>
				</view>
			</u-form-item>
		</u-form>
		<login-type />
		<view class="login-btn" @click="submit">立即登录</view>
		<u-verification-code :seconds="60" ref="uCode" @start="codeStart" @end="codeEnd" @change="codeChange"
			start-text="获取验证码" change-text="X秒" />
	</view>
</template>

<script>
	import LoginType from '../LoginType'
	import {
		mapGetters,
		mapMutations,
		mapActions
	} from 'vuex'

	export default {
		components: {
			'login-type': LoginType,
		},
		data() {
			return {
				form: {
					mobile: '',
					validateCode: '',
				},
				rules: {
					mobile: [{
						required: true,
						message: '请输入手机号',
						trigger: ['change', 'blur'],
					}],
					validateCode: [{
						required: true,
						message: '请输入验证码',
						trigger: ['change', 'blur'],
					}]
				},
				is_sendCode: false, //是否发送验证码
				tips: '',
			};
		},
		computed: {
			...mapGetters({
				currLoginType: 'loginConfig/currLoginType',
				agreeUser: 'loginConfig/agreeUser'
			})
		},
		inject: ['showSlideCode', 'getSession', 'getRegPayIns', 'getRedirect', 'getPid'],
		mounted() {
			this.$refs.uForm.setRules(this.rules)
		},
		methods: {
			...mapActions([
				'getUserInfo'
			]),
			...mapMutations({
				setShowAgreePopup: 'loginConfig/setShowAgreePopup',
				setIsThirdLogin: 'loginConfig/setIsThirdLogin',
			}),
			submit() {
				this.$refs.uForm.validate(valid => {
					if (valid) {
						if (!this.agreeUser) {
							// this.$util.msg('请先阅读并同意用户协议和隐私政策');
							this.setShowAgreePopup(true)
							this.setIsThirdLogin(false)
							return;
						}
						this.doLogin()
					} else {
						console.log('验证失败');
					}
				});
			},
			async doLogin() {
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				const {
					reg_status,
					reg_data,
					token,
				} = await this.$u.api.login({
					session: this.getSession(),
					validateCode: this.form.validateCode,
					mobile: this.form.mobile,
					login_type: 2,
					pid: this.getPid()
				})
				uni.hideLoading()
				if (reg_status == 1) {
					this.getRegPayIns().show({
						reg_code: reg_data.reg_code
					})
				} else {
					//存储token
					uni.setStorageSync('token', token)
					this.$u.vuex('token', token)
					this.$util.msg('登录成功')
					await this.getUserInfo()

					setTimeout(() => {
						if (this.getRedirect())
							this.$util.redirect(this.getRedirect())
						else
							this.$util.back()
					}, 1500)
				}
			},
			codeStart() {
				this.is_sendCode = true;
			},
			codeEnd() {
				this.is_sendCode = false;
			},
			codeChange(text) {
				this.tips = text
			},
			//发送验证码
			sendCode() {
				if (!this.$u.test.mobile(this.form.mobile)) return this.$u.toast('请输入正确的手机号码')
				uni.$once('verifySuccess', this.verifySuccess)
				this.showSlideCode()
			},
			// 验证成功
			async verifySuccess() {
				if (this.currLoginType != 'mobile')
					return
				if (this.$refs.uCode.canGetCode) {
					// 模拟向后端请求验证码
					uni.showLoading({
						title: '正在获取验证码'
					})

					let data = {
						send_type: 10,
						mobile: this.form.mobile,
						session: this.getSession(),
					}
					await this.$u.api.sendCode(data)
					uni.hideLoading()
					this.$u.toast('验证码已发送')
					this.$refs.uCode.start()
				} else {
					this.$u.toast('倒计时结束后再发送');
				}
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.login-form {
		::v-deep {
			.u-input {
				background: #F0F3F7;
				border-radius: 40rpx;
				padding: 0 40rpx 0 40rpx !important;
			}
		}
	}

	.login-btn {
		height: 46px;
		background: linear-gradient(90deg, #fe8a55, #ff5d4d);
		border-radius: 24px;
		font-weight: 500;
		color: #fff;
		font-size: 16px;
		display: flex;
		justify-content: center;
		align-items: center;
		margin-top: 40px;
	}

	.input-block {
		position: relative;
		width: 100%;

		.code-btn {
			position: absolute;
			z-index: 5;
			color: red;
			top: 4rpx;
			right: 30rpx;
		}

		.waiting {
			color: #c3c8d9;
		}
	}
</style>