<template>
	<view class="login-form">
		<u-form :model="form" ref="uForm" :label-width="0" :error-type="['toast']" :border-bottom="false">
			<u-form-item prop="username" :border-bottom="false">
				<u-input v-model="form.username" placeholder="请输入登录账号" :height="80" />
			</u-form-item>
			<u-form-item prop="pwd" :border-bottom="false">
				<u-input v-model="form.pwd" type="password" placeholder="请输入登录密码" :height="80" />
			</u-form-item>
		</u-form>
		<login-type />
		<view class="login-btn" @click="submit">立即登录</view>
	</view>
</template>

<script>
	import LoginType from '../LoginType'
	import {
		mapGetters,
		mapMutations,
		mapActions
	} from 'vuex'

	export default {
		components: {
			'login-type': LoginType,
		},
		data() {
			return {
				form: {
					username: '',
					pwd: '',
				},
				rules: {
					username: [{
						required: true,
						message: '请输入登录账号',
						trigger: ['change', 'blur'],
					}],
					pwd: [{
						required: true,
						message: '请输入登录密码',
						trigger: ['change', 'blur'],
					}]
				},
			};
		},
		computed: {
			...mapGetters({
				currLoginType: 'loginConfig/currLoginType',
				agreeUser: 'loginConfig/agreeUser',
				showAgreePopup: 'loginConfig/showAgreePopup'
			})
		},
		inject: ['showSlideCode', 'getSession', 'getRedirect', 'getRegPayIns', 'getPid'],
		mounted() {
			this.$refs.uForm.setRules(this.rules)
			if (process.env.NODE_ENV === 'development') {
				this.form.username = 'test'
				this.form.pwd = '123123'
			}
		},
		methods: {
			...mapActions([
				'getUserInfo'
			]),
			...mapMutations({
				setShowAgreePopup: 'loginConfig/setShowAgreePopup',
				setIsThirdLogin: 'loginConfig/setIsThirdLogin',
			}),
			submit() {
				this.$refs.uForm.validate(async (valid) => {
					if (valid) {
						if (!this.agreeUser) {
							// this.$util.msg('请先阅读并同意用户协议和隐私政策');
							this.setShowAgreePopup(true)
							this.setIsThirdLogin(false)
							return;
						}
						const flag = await this.getIsCaptcha()
						if (flag) {
							uni.$once('verifySuccess', this.verifySuccess)
							this.showSlideCode()
						} else {
							this.doLogin()
						}
					} else {
						console.log('验证失败');
					}
				});
			},
			// 获取是否需要滑块验证
			getIsCaptcha() {
				return new Promise((resolve, reject) => {
					this.$u.api.is_captcha({
						account: this.form.username,
					}).then((res) => {
						if (res.is_captcha) resolve(true)
						else resolve(false)
					}).catch(e => {
						reject(e)
					})
				})
			},
			async doLogin() {
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				const {
					reg_status,
					reg_data,
					token,
				} = await this.$u.api.login({
					username: this.form.username,
					password: this.form.pwd,
					session: this.getSession(),
					login_type: 1,
					pid: this.getPid()
				})
				uni.hideLoading()
				if (reg_status == 1) {
					this.getRegPayIns().show({
						reg_code: reg_data.reg_code
					})
				} else {
					//存储token
					uni.setStorageSync('token', token)
					this.$u.vuex('token', token)
					this.$util.msg('登录成功')
					await this.getUserInfo()

					setTimeout(() => {


						if (this.getRedirect())
							// #ifdef H5
							window.location.href = this.getRedirect()
						// #endif

						// #ifndef H5
						this.$util.redirect(this.getRedirect())
						// #endif
						// this.$util.redirect(this.redirect)
						else
							// #ifdef H5
							window.location.href = '/pages/index/index'
						// #endif

						// #ifndef H5
						this.$util.back()
						// #endif
					}, 1500)
				}
			},
			// 验证成功
			async verifySuccess() {
				if (this.currLoginType != 'password')
					return
				this.doLogin()
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.login-form {
		::v-deep {
			.u-input {
				background: #F0F3F7;
				border-radius: 40rpx;
				padding: 0 40rpx 0 40rpx !important;
			}
		}
	}

	.login-btn {
		height: 46px;
		background: linear-gradient(90deg, #fe8a55, #ff5d4d);
		border-radius: 24px;
		font-weight: 500;
		color: #fff;
		font-size: 16px;
		display: flex;
		justify-content: center;
		align-items: center;
		margin-top: 40px;
	}

	.input-block {
		position: relative;
		width: 100%;

		.code-btn {
			position: absolute;
			color: red;
			top: 4rpx;
			right: 30rpx;
		}

		.waiting {
			color: #c3c8d9;
		}
	}
</style>