<template>
	<view class="op-box">
		<view class="login-type">
			<text v-for="item,index in list" :key="index" @click="setCurrLoginType(item.key)">{{item.label}}</text>
		</view>
		<view v-if="currLoginType == 'password'" @click="forgetPass">
			忘记密码
		</view>
	</view>
</template>

<script>
	import {
		mapGetters,
		mapMutations
	} from 'vuex'
	export default {
		components: {

		},
		props: {

		},
		data() {
			return {}
		},
		computed: {
			...mapGetters({
				loginTypeList: 'loginConfig/loginTypeList',
				currLoginType: 'loginConfig/currLoginType',
				retrievePasswordConfigType: 'loginConfig/retrievePasswordConfigType'
			}),
			list() {
				return _.filter(this.loginTypeList, (item) => {
					return item.key != this.currLoginType
				})
			}
		},
		methods: {
			...mapMutations({
				setCurrLoginType: 'loginConfig/setCurrLoginType'
			}),
			forgetPass() {
				if (!this.retrievePasswordConfigType.length) {
					this.$util.msg('系统未设置密码找回方式')
					return
				}
				this.$util.on('/pages/user/resetpsw')
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.op-box {
		width: 100%;
		display: flex;
		align-items: center;
		justify-content: space-between;
		color: #ff594d;
		font-weight: 400;
		font-size: 28rpx;

		.login-type {
			display: flex;
			flex: 1;
			gap: 20rpx;
		}
	}
</style>