<template>
	<u-popup v-model="show" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}" :border-radius="20"
		width="500rpx" :closeable="true" @close="close">
		<view class="popup-content">
			<view class="title">
				{{title}}
			</view>
			<view class="qrcode" v-if="qrcodeurl">
				<uqrcode ref="uqrcode" canvas-id="qrcode" :hide="!qrcode_image_show"  :loading="true" v-if="!qrcode_image_show" @complete="uqrcodeComplete"
					sizeUnit="rpx" size="400" :value="qrcodeurl"></uqrcode>
				<image style="width: 100%;height: 100%;" v-if="qrcode_image_show" :src="qrcode_image" mode="aspectFit">
				</image>
			</view>
			<view @click="copyLink"><view  v-if="copymark">收款人姓名2： <text style="color:red">{{copymark}}</text></view><text v-else>点击复制链接或截图扫码</text></view>
		
		</view>
	</u-popup>
</template>

<script>
	export default {
		props: {
			qrcodeshow: {
				type: Boolean,
				default: false
			},
			title: {
				type: String,
				default: '',
			},
			qrcodeurl: {
				type: String,
				default: '',
			},
			copymark: {
				type: String,
				default: '',
			}
		},
		data() {
			return {
				show: false,
				qrcode_image_show: false,
			}
		},
		watch: {
			qrcodeshow: {
				handler(nv) {
					this.show = this.qrcodeshow
				},
			}
		},
		mounted() {

		},
		methods: {
			//二维码生成成功
			uqrcodeComplete(e) {
				this.$refs.uqrcode.toTempFilePath({
					success: res => {
						this.qrcode_image_show = true
						this.qrcode_image = res.tempFilePath

					}
				});
			},
			close() {
				this.$emit('update:qrcodeshow', false)
				this.$emit('close')
			},
			copyLink() {
				uni.setClipboardData({
					data: this.qrcodeurl,
					success() {
						uni.showToast({
							title: '复制成功',
							icon: 'success'
						});
					},
					fail() {
						uni.showToast({
							title: '复制失败',
							icon: 'none'
						});
					}
				});
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		display: flex;
		align-items: center;
		padding: 40rpx;
		flex-direction: column;
		gap: 20rpx;

		.qrcode {
			width: 400rpx;
			height: 400rpx;
		}
	}
</style>